Функция ПолучитьСальдоСчета(СчетСсылка)

	Запрос = Новый Запрос;
	Запрос.Текст = 
	"ВЫБРАТЬ
	|	ЕСТЬNULL(СУММА(ВЫБОР
	|			КОГДА Хозрасчетный.СчетДт В ИЕРАРХИИ (&Счет)
	|				ТОГДА Хозрасчетный.Сумма
	|			ИНАЧЕ 0
	|		КОНЕЦ), 0) КАК ОборотДт,
	|	ЕСТЬNULL(СУММА(ВЫБОР
	|			КОГДА Хозрасчетный.СчетКт В ИЕРАРХИИ (&Счет)
	|				ТОГДА Хозрасчетный.Сумма
	|			ИНАЧЕ 0
	|		КОНЕЦ), 0) КАК ОборотКт
	|ИЗ
	|	РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
	|ГДЕ
	|	Хозрасчетный.СчетДт В ИЕРАРХИИ (&Счет)
	|	ИЛИ Хозрасчетный.СчетКт В ИЕРАРХИИ (&Счет)";

	Запрос.УстановитьПараметр("Счет", СчетСсылка);

	Выборка = Запрос.Выполнить().Выбрать();

	ОборотДт = 0;
	ОборотКт = 0;

	Если Выборка.Следующий() Тогда
		ОборотДт = Выборка.ОборотДт;
		ОборотКт = Выборка.ОборотКт;
	КонецЕсли;

	Если СчетСсылка.Вид = ВидСчета.Пассивный Тогда
		Возврат ОборотКт - ОборотДт;
	Иначе
		Возврат ОборотДт - ОборотКт;
	КонецЕсли;

КонецФункции
